import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import API from "../api/axios";

function RegisterPage() {
  const [formData, setFormData] = useState({
    fullname: "",
    email: "",
    password: "",
    confirmPassword: "",
  });

  const [errors, setErrors] = useState({});
  const [apiError, setApiError] = useState("");

  const navigate = useNavigate();

  const handleChange = (e) => {
    const { id, value } = e.target;
    setFormData({ ...formData, [id]: value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setApiError("");

    // Simple validation
    let newErrors = {};
    if (!formData.fullname) newErrors.fullname = "Name required";
    if (!formData.email) newErrors.email = "Email required";
    if (!formData.password) newErrors.password = "Password required";
    if (formData.password !== formData.confirmPassword)
      newErrors.confirmPassword = "Passwords do not match";

    setErrors(newErrors);
    if (Object.keys(newErrors).length > 0) return;

    try {
      await API.post("/auth/register", {
        name: formData.fullname,
        email: formData.email,
        password: formData.password,
      });
      alert("Registration successful!");
      navigate("/login");
    } catch (err) {
      setApiError(err.response?.data?.message || "Registration failed");
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <input id="fullname" placeholder="Full Name" onChange={handleChange} />
      <p>{errors.fullname}</p>

      <input id="email" placeholder="Email" onChange={handleChange} />
      <p>{errors.email}</p>

      <input id="password" type="password" placeholder="Password" onChange={handleChange} />
      <p>{errors.password}</p>

      <input id="confirmPassword" type="password" placeholder="Confirm Password" onChange={handleChange} />
      <p>{errors.confirmPassword}</p>

      {apiError && <p>{apiError}</p>}
      <button type="submit">Register</button>
    </form>
  );
}

export default RegisterPage;
